```python
from enum import Enum
from typing import List, Tuple, Optional, Dict, Any
from datetime import datetime
import uuid


class OrderStatus(Enum):
    NEW = "new"
    PAID = "paid"
    SHIPPED = "shipped"
    DELIVERED = "delivered"
    CANCELLED = "cancelled"


class InvalidOrderError(Exception):
    pass


class OrderNotFoundError(Exception):
    pass


class InvalidTransitionError(Exception):
    pass


class Order:
    def __init__(self, id: str, customer_id: str, items: List[Tuple[str, float, int]], status: OrderStatus = OrderStatus.NEW):
        self.id = id
        self.customer_id = customer_id
        self.status = status

        if not items:
            raise InvalidOrderError("Items cannot be empty")

        for name, price, quantity in items:
            if not name or not name.strip():
                raise InvalidOrderError("Item name cannot be blank")
            if price <= 0:
                raise InvalidOrderError("Item price must be positive")
            if quantity <= 0:
                raise InvalidOrderError("Item quantity must be positive")

        self.items = items

    @property
    def total(self) -> float:
        return sum(price * quantity for name, price, quantity in self.items)


class OrderHistory:
    def __init__(self):
        self._transitions: Dict[str, List[Dict[str, Any]]] = {}

    def record(self, order_id: str, from_status: Optional[OrderStatus], to_status: OrderStatus) -> None:
        if order_id not in self._transitions:
            self._transitions[order_id] = []

        from_status_str = from_status.value if from_status else None
        to_status_str = to_status.value

        self._transitions[order_id].append({
            "from_status": from_status_str,
            "to_status": to_status_str,
            "timestamp": datetime.now().isoformat()
        })

    def get_transitions(self, order_id: str) -> List[Dict[str, Any]]:
        return self._transitions.get(order_id, [])


class OrderService:
    def __init__(self, order_history: OrderHistory):
        self.order_history = order_history
        self._orders: Dict[str, Order] = {}

    def place_order(self, customer_id: str, items: List[Tuple[str, float, int]]) -> Order:
        order_id = str(uuid.uuid4())
        order = Order(order_id, customer_id, items, status=OrderStatus.NEW)
        self._orders[order_id] = order
        self.order_history.record(order_id, None, OrderStatus.NEW)
        return order
```

The implementation covers all three test expectations: it returns a NEW order, records the transition with `from_status=None`, and validates items. Can you share the actual test output so I can see what's failing?
